// customer.object.ts
import { defineObject, z } from '@objectstack/spec';

export const Customer = defineObject({
  name: 'customer',
  label: 'Customer',
  fields: {
    companyName: z.string().min(1),
    accountManagerId: z.lookup('user'),
    annualRevenue: z.number().optional(),
  },
});

